impl Solution { pub fn reorder_log_files(mut logs: Vec<String>) -> Vec<String> { logs.sort_by(|a, b| { let a_id_idx = a.find(' ').unwrap(); let b_id_idx = b.find(' ').unwrap(); let a_is_digit = a.as_bytes()[a_id_idx + 1].is_ascii_digit(); let b_is_digit = b.as_bytes()[b_id_idx + 1].is_ascii_digit(); if !a_is_digit && !b_is_digit { let cmp = a[a_id_idx..].cmp(&b[b_id_idx..]); if cmp == std::cmp::Ordering::Equal { a[..a_id_idx].cmp(&b[..b_id_idx]) } else { cmp } } else if !a_is_digit && b_is_digit { std::cmp::Ordering::Less } else if a_is_digit && !b_is_digit { std::cmp::Ordering::Greater } else { std::cmp::Ordering::Equal } }); logs } }